// ============================================================
// CONFIGURATION — edit these values before activating
// ============================================================

// Your n8n public webhook base URL — no trailing slash
// Example: 'https://n8n.yourdomain.com/webhook'
const webhookBaseUrl = 'https://YOUR-N8N-DOMAIN.com/webhook';

// Your email address — used as the From address on ping emails
const pmEmail = 'your@email.com';

// Do not edit below this line
return [{ json: { webhookBaseUrl, pmEmail } }];

const items = $input.all();
const results = [];

const config = $('Config').first().json;
const base = config.webhookBaseUrl || 'https://YOUR-N8N-DOMAIN.com/webhook';
const statusUrl = `${base}/vendor-status`;

function generateToken() {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  let token = '';
  for (let i = 0; i < 32; i++) {
    token += chars[Math.floor(Math.random() * chars.length)];
  }
  return token;
}

for (const item of items) {
  const vendor = item.json;

  if (!vendor.vendor_id) {
    throw new Error(`Missing vendor_id for: ${vendor.vendor_name || 'unnamed row'}. vendor_id is required.`);
  }
  if (!vendor.contact_email) {
    throw new Error(`Missing contact_email for vendor_id: ${vendor.vendor_id}. Add an email or set status to Inactive.`);
  }

  const token = generateToken();
  const vendorId = encodeURIComponent(vendor.vendor_id);
  const project = encodeURIComponent(vendor.project_name || 'Project');

  const makeLink = (status) =>
    `${statusUrl}?vendor_id=${vendorId}&status=${encodeURIComponent(status)}&token=${token}&project=${project}`;

  results.push({
    json: {
      ...vendor,
      ping_token: token,
      ping_sent_at: new Date().toISOString(),
      pm_email: config.pmEmail || vendor.pm_email,
      link_on_track: makeLink('On Track'),
      link_at_risk: makeLink('At Risk'),
      link_delayed: makeLink('Delayed'),
      link_needs_pm: makeLink('Needs PM Input')
    }
  });
}

return results;

