const params = $('When Vendor Clicks Status Link').first().json.query;
const vendors = $input.all();

const vendorId = decodeURIComponent(params.vendor_id || '');
const submittedToken = params.token || '';
const status = decodeURIComponent(params.status || '');
const project = decodeURIComponent(params.project || '');

const allowedStatuses = ['On Track', 'At Risk', 'Delayed', 'Needs PM Input'];
if (!allowedStatuses.includes(status)) {
  return [{ json: { valid: false, reason: 'Invalid status value', vendorId, status, project } }];
}

const vendorRow = vendors.find(v => v.json.vendor_id === vendorId);

if (!vendorRow) {
  return [{ json: { valid: false, reason: 'Vendor not found', vendorId, status, project } }];
}

const vendor = vendorRow.json;
const storedToken = vendor.ping_token || '';

if (!storedToken || storedToken !== submittedToken) {
  return [{ json: { valid: false, reason: 'Invalid or expired token', vendorId, status, project, vendor_name: vendor.vendor_name } }];
}

return [{
  json: {
    valid: true,
    vendor_id: vendorId,
    vendor_name: vendor.vendor_name,
    project_name: vendor.project_name || project,
    status,
    responded_at: new Date().toISOString()
  }
}];

const data = $('Validate Token and Status').first().json;

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

const statusColors = {
  'On Track': '#1D9E75',
  'At Risk': '#BA7517',
  'Delayed': '#C8392B',
  'Needs PM Input': '#1a1a1a'
};
const color = statusColors[data.status] || '#1a1a1a';

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;background:#f4f3ef;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:24px}.card{background:#fff;border:1px solid #e0e0e0;border-radius:4px;width:100%;max-width:420px;overflow:hidden}.header{background:#1a1a1a;padding:18px 24px}.header h1{color:#fff;font-size:16px;font-weight:600}.body{padding:20px 24px}.badge{display:inline-block;background:${color};color:#fff;padding:5px 12px;border-radius:3px;font-size:12px;font-weight:600;margin-bottom:14px}.detail{font-size:12px;color:#777;margin-bottom:5px}.footer{padding:12px 24px;border-top:1px solid #e0e0e0}.footer p{font-size:10px;color:#aaa}.footer a{color:#aaa}</style></head><body><div class="card"><div class="header"><h1>Status received. Thank you.</h1></div><div class="body"><span class="badge">${escapeHtml(data.status)}</span><p class="detail">Project: ${escapeHtml(data.project_name)}</p><p class="detail">Vendor: ${escapeHtml(data.vendor_name)}</p></div><div class="footer"><p>Powered by <a href="https://pmexecution.com">PM Execution Tools</a></p></div></div></body></html>`;

return [{ json: { ...data, confirmationHtml: html } }];
